sql:
SELECT sequence_id, share_date
FROM sequence_shares
WHERE shared_with_id = 1;

SELECT statistic_name
FROM sequence_statistics
WHERE sequence_id = 0;

SELECT COUNT(*) 
FROM sequence_statistics 
WHERE sequence_id = 0 AND calculated_date >= '2023-01-01';

SELECT sequence_id, COUNT(*) AS number_of_statistics
FROM sequence_statistics
GROUP BY sequence_id;

SELECT COUNT(*) 
FROM sequence_shares
WHERE shared_with_id = 1;

SELECT access_level, COUNT(*) as number_of_shares
FROM sequence_shares
GROUP BY access_level;

SELECT COUNT(*) as num_shares
FROM sequence_shares
WHERE owner_id = 1;

external_knowledge:
; Shared sequences refer to sequences that have been shared by their owners with other users, as indicated by the presence of a shared_with_id in the sequence_shares table; 
; User operations pertain to actions performed by users on sequences, such as creating or editing them; 
; Sequence statistics are calculated values associated with sequences, such as performance metrics or usage data.

sql:
SELECT DISTINCT shared_with_id
FROM sequence_shares
WHERE access_level = 'edit';

SELECT user_name
FROM users
WHERE user_id = (SELECT created_by FROM sequences WHERE sequence_id = 0);
